BEGIN;

-- Resolver el tenant IDIC (falla explicitamente si no existe).
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM tenant WHERE codigo='IDIC') THEN
    RAISE EXCEPTION 'No existe tenant IDIC; ejecute el seed base antes.';
  END IF;
END $$;

-- ---------------------------------------------------------------- STAGING
CREATE TEMP TABLE stg_gg        (codigo text, nombre text) ON COMMIT DROP;
