CREATE TEMP TABLE stg_fam       (codsucdel text, nombre text, laboratorio text, departamento text, subdireccion text) ON COMMIT DROP;
CREATE TEMP TABLE stg_elem      (codigo text, nombre text, cntlroom text, codsucdel text, servgrp text) ON COMMIT DROP;
CREATE TEMP TABLE stg_ens       (codigo text, nombre text, precio numeric, codsucdel text, agrupado text, objetivo text, intrabajo text) ON COMMIT DROP;
CREATE TEMP TABLE stg_met       (codigo text, nombre text, ensayo_codigo text, norma text, instrumento text, version text, servgrp text) ON COMMIT DROP;
CREATE TEMP TABLE stg_ana       (metodo_codigo text, codigo text, nombre text, unidad text, formula text, rmin text, rnom text, rmax text) ON COMMIT DROP;
CREATE TEMP TABLE stg_espec     (metodo_codigo text, analito_codigo text, ambito text, limite_inf text, nominal text, limite_sup text, requisitos text, texto text, unidad text, dedupe_key text) ON COMMIT DROP;
CREATE TEMP TABLE stg_panel     (elemento_codigo text, metodo_codigo text, inspec_tipo text, orden int) ON COMMIT DROP;

