243,Cloruro Hormigon,Cloruro Hormigon,,":DECLARE FORM1,FORM2,v1v2,v21v2; :IF Len(sSql)= 3; v1v2:= Val(sSql[1,2]) - Val(sSql[2,2]) ; v21v2:= (2 * Val(sSql[1,2])) - Val(sSql[2,2]) ; :IF ( Val(sSql[3,2]) * v1v2 ) <> 0; FORM1:= ( ( 0.03546 * v21v2 ) / ( Val(sSql[3,2]) * v1v2 ) ) * 100; Acum := Acum + FORM1; :ENDIF; :ELSE; UsrMes(""Mensaje"",""Falta ingresar valores a Los parámetros en Lectura No. ""+Str(Lect[k,1])); :ENDIF;",,,
