4734,Tiempo de retardo,Tiempo de retardo,s,":PARAMETERS PCT; :DECLARE sSql, Den, FORMULA, CANTIDAD, k, Lect, Acum; :IF prmcount() = 0; :DECLARE PCT; PCT := .F.; :ENDIF; :IF LimsType(""Resu"") = ""U""; :DECLARE Resu; :ENDIF; CANTIDAD := Val(GetCurrent(""RENOR"",""QTTY"")); FORMULA := SqlExecute(""Select ANALYTE From ANALFIELDS,TESTS where TESTS.TESTCODE = ANALFIELDS.TESTCODE AND TESTS.TESTCODE =?CURRENT_TESTCODE? AND ANALYTE= ?CURRENT_ANALYTE?""); Resu := 0; :IF Len(FORMULA) > 0; :IF CANTIDAD = 1; Lect := SqlExecute("" Select NLECTURA from LECTURAS where TESTCODE=?CURRENT_TESTCODE? and ANALYTE =?CURRENT_ANALYTE? and ORDNO = ?CURRENT_ORDNO? and REP=?CURRENT_REP?""); :IF Empty(Lect); AddRecord(""LECTURAS"",{""ANALYTE"",""ORDNO"",""REP"",""TESTCODE""},{CURRENT_ANALYTE,CURRENT_ORDNO,CURRENT_REP,CURRENT_TESTCODE}); :ENDIF; ExecFunction(""ExecComp"",{CURRENT_ANALYTE,1}); :ELSE; ExecFunction(""CALLRAWTABLE""); :ENDIF; :ELSE; UsrMes(""Error"",""Faltan por definir los componentes de la formulación, Verifique con el Administrador del Sistema""); :RETURN -1; :ENDIF; Lect := SqlExecute("" Select NLECTURA from LECTURAS where TESTCODE=?CURRENT_TESTCODE? and ANALYTE =?CURRENT_ANALYTE? and ORDNO = ?CURRENT_ORDNO? and REP=?CURRENT_REP?""); FORMULA := LSearch(""Select FORMULA From ANALYTES where TESTCODE = ""+CURRENT_TESTCODE+"" AND ANALYTE= '""+CURRENT_ANALYTE+""'""); k:=1; Acum :=0; :WHILE k<=Len(Lect); sSql := SqlExecute("" Select CAMPO, VALOR from DET_LECTURA where TESTCODE=?CURRENT_TESTCODE? and ANALYTE =?CURRENT_ANALYTE? and ORDNO = ?CURRENT_ORDNO? and REP=?CURRENT_REP? and NLECTURA=?Lect[k,1]? order by CAMPO""); ExecUDF(FORMULA); k:=k+1; :ENDWHILE; :IF K - 1 > 0; Resu := Acum / (k - 1); :IF PCT; Resu := Resu * 100; :ENDIF; :ENDIF; :IF EMPTY(MULRES); MULRES:=VAL(GETCURRENT(""RENOR"",""NUMRES"")); :ENDIF; :IF MULRES>0; Resu:=MULRES; :ENDIF; Resu",,,
