-- --------------------------------------------------- CARGA cat_* (UPSERT)
WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_gran_grupo (tenant_id, codigo, nombre)
SELECT t.id, s.codigo, s.nombre FROM stg_gg s CROSS JOIN t
ON CONFLICT (tenant_id, codigo) DO UPDATE SET nombre = EXCLUDED.nombre;

WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_grupo (tenant_id, gran_grupo_id, cgrupo, nombre)
SELECT t.id, gg.id, s.cgrupo, s.nombre
FROM stg_grupo s CROSS JOIN t
JOIN cat_gran_grupo gg ON gg.tenant_id = (SELECT id FROM t) AND gg.codigo = s.gg_codigo
ON CONFLICT (tenant_id, gran_grupo_id, cgrupo) DO UPDATE SET nombre = EXCLUDED.nombre;

WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_subgrupo (tenant_id, grupo_id, cntlroom, nombre)
SELECT t.id, g.id, s.cntlroom, s.nombre
FROM stg_sub s CROSS JOIN t
JOIN cat_gran_grupo gg ON gg.tenant_id = (SELECT id FROM t) AND gg.codigo = s.gg_codigo
JOIN cat_grupo g       ON g.tenant_id  = (SELECT id FROM t) AND g.gran_grupo_id = gg.id AND g.cgrupo = s.cgrupo
ON CONFLICT (tenant_id, cntlroom) DO UPDATE SET grupo_id = EXCLUDED.grupo_id, nombre = EXCLUDED.nombre;

WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_familia (tenant_id, codsucdel, nombre, laboratorio, departamento, subdireccion)
SELECT t.id, s.codsucdel, s.nombre, NULLIF(s.laboratorio,''), NULLIF(s.departamento,''), NULLIF(s.subdireccion,'')
FROM stg_fam s CROSS JOIN t
ON CONFLICT (tenant_id, codsucdel) DO UPDATE
  SET nombre = EXCLUDED.nombre, laboratorio = EXCLUDED.laboratorio,
      departamento = EXCLUDED.departamento, subdireccion = EXCLUDED.subdireccion;

WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_elemento (tenant_id, subgrupo_id, familia_id, codigo, nombre, servgrp)
SELECT t.id, sg.id, f.id, s.codigo, s.nombre, NULLIF(s.servgrp,'')
FROM stg_elem s CROSS JOIN t
JOIN cat_subgrupo sg ON sg.tenant_id = (SELECT id FROM t) AND sg.cntlroom = s.cntlroom
LEFT JOIN cat_familia f ON f.tenant_id = (SELECT id FROM t) AND f.codsucdel = s.codsucdel
ON CONFLICT (tenant_id, codigo) DO UPDATE
  SET subgrupo_id = EXCLUDED.subgrupo_id, familia_id = EXCLUDED.familia_id, nombre = EXCLUDED.nombre, servgrp = EXCLUDED.servgrp;

WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_ensayo (tenant_id, codigo, nombre, precio, familia_id, agrupado, objetivo, instruccion_trabajo)
SELECT t.id, s.codigo, s.nombre, COALESCE(s.precio,0), f.id,
       NULLIF(s.agrupado,''), NULLIF(s.objetivo,''), NULLIF(s.intrabajo,'')
FROM stg_ens s CROSS JOIN t
LEFT JOIN cat_familia f ON f.tenant_id = (SELECT id FROM t) AND f.codsucdel = s.codsucdel
ON CONFLICT (tenant_id, codigo) DO UPDATE
  SET nombre = EXCLUDED.nombre, precio = EXCLUDED.precio, familia_id = EXCLUDED.familia_id,
      agrupado = EXCLUDED.agrupado, objetivo = EXCLUDED.objetivo, instruccion_trabajo = EXCLUDED.instruccion_trabajo;

WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_metodo (tenant_id, ensayo_id, codigo, nombre, norma, instrumento, version, servgrp)
SELECT t.id, e.id, s.codigo, s.nombre, NULLIF(s.norma,''), NULLIF(s.instrumento,''), NULLIF(s.version,''), NULLIF(s.servgrp,'')
FROM stg_met s CROSS JOIN t
LEFT JOIN cat_ensayo e ON e.tenant_id = (SELECT id FROM t) AND e.codigo = s.ensayo_codigo
ON CONFLICT (tenant_id, codigo) DO UPDATE
  SET ensayo_id = EXCLUDED.ensayo_id, nombre = EXCLUDED.nombre, norma = EXCLUDED.norma,
      instrumento = EXCLUDED.instrumento, version = EXCLUDED.version, servgrp = EXCLUDED.servgrp;

WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_analito (tenant_id, metodo_id, codigo, nombre, unidad, formula, rango_min, rango_nominal, rango_max)
SELECT t.id, m.id, s.codigo, s.nombre, NULLIF(s.unidad,''), NULLIF(s.formula,''),
       NULLIF(s.rmin,''), NULLIF(s.rnom,''), NULLIF(s.rmax,'')
FROM stg_ana s CROSS JOIN t
JOIN cat_metodo m ON m.tenant_id = (SELECT id FROM t) AND m.codigo = s.metodo_codigo
ON CONFLICT (tenant_id, metodo_id, codigo) DO UPDATE
  SET nombre = EXCLUDED.nombre, unidad = EXCLUDED.unidad, formula = EXCLUDED.formula,
      rango_min = EXCLUDED.rango_min, rango_nominal = EXCLUDED.rango_nominal, rango_max = EXCLUDED.rango_max;

WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_especificacion (tenant_id, analito_id, ambito, limite_inf, nominal, limite_sup, requisitos, texto, unidad, dedupe_key)
SELECT t.id, a.id, s.ambito, NULLIF(s.limite_inf,''), NULLIF(s.nominal,''), NULLIF(s.limite_sup,''),
       NULLIF(s.requisitos,''), NULLIF(s.texto,''), NULLIF(s.unidad,''), s.dedupe_key
FROM stg_espec s CROSS JOIN t
JOIN cat_metodo  m ON m.tenant_id = (SELECT id FROM t) AND m.codigo = s.metodo_codigo
JOIN cat_analito a ON a.tenant_id = (SELECT id FROM t) AND a.metodo_id = m.id AND a.codigo = s.analito_codigo
ON CONFLICT (tenant_id, analito_id, dedupe_key) DO NOTHING;

WITH t AS (SELECT id FROM tenant WHERE codigo='IDIC')
INSERT INTO cat_panel (tenant_id, elemento_id, metodo_id, ensayo_id, inspec_tipo, orden)
SELECT t.id, e.id, m.id, m.ensayo_id, NULLIF(s.inspec_tipo,''), s.orden
FROM stg_panel s CROSS JOIN t
JOIN cat_elemento e ON e.tenant_id = (SELECT id FROM t) AND e.codigo = s.elemento_codigo
JOIN cat_metodo   m ON m.tenant_id = (SELECT id FROM t) AND m.codigo = s.metodo_codigo
ON CONFLICT (tenant_id, elemento_id, metodo_id) DO UPDATE
  SET ensayo_id = EXCLUDED.ensayo_id, inspec_tipo = EXCLUDED.inspec_tipo, orden = EXCLUDED.orden;

COMMIT;

